9	using namespace coinbase::mpc;
10	
11	namespace coinbase::mpc::ecdsampc {
12	
13	// These macros help with the readability of the code to make it easier to match the spec and the code
14	#define _ij msgs[j]
15	#define _i msg
16	#define _j received(j)
17	#define _js all_received()
18	
19	error_t dkg(job_mp_t& job, ecurve_t curve, key_t& key, buf_t& sid) {
20	  return eckey::key_share_mp_t::dkg(job, curve, key, sid);
21	}
