87	void converter_t::convert(std::string& value) {
88	  if (write) {
89	    // serialization length validation
90	    cb_assert(value.length() <= SHRT_MAX);
91	  }
92	
93	  short value_size = (short)value.length();
94	  convert(value_size);
95	
96	  if (write) {
97	    if (pointer) memmove(current(), value.data(), value_size);
98	  } else {
99	    if (value_size < 0) {
100	      set_error();
101	      return;
102	    }  // deserialization length validation
103	
104	    if (is_error() || !at_least(value_size)) {
105	      set_error();
106	      return;
107	    }
108	    value.resize(value_size);
109	    memmove(value.data(), current(), value_size);
110	  }
111	  forward(value_size);
