131	void converter_t::convert_len(uint32_t& len) {
132	  byte_t b = 0;
133	  if (write) {
134	    cb_assert(len <= MAX_CONVERT_LEN);
135	    if (len <= 0x7f) {
136	      b = byte_t(len);
137	      convert(b);
138	      return;
139	    }
140	    if (len <= 0x3fff) {
141	      b = byte_t(len >> 8) | 0x80;
142	      convert(b);
143	      b = byte_t(len);
144	      convert(b);
145	      return;
146	    }
147	    if (len <= 0x1fffff) {
148	      b = byte_t(len >> 16) | 0xc0;
149	      convert(b);
150	      b = byte_t(len >> 8);
151	      convert(b);
152	      b = byte_t(len);
153	      convert(b);
154	      return;
155	    }
156	    b = byte_t(len >> 24) | 0xe0;
157	    convert(b);
158	    b = byte_t(len >> 16);
159	    convert(b);
160	    b = byte_t(len >> 8);
161	    convert(b);
162	    b = byte_t(len);
163	    convert(b);
164	  } else {
165	    convert(b);
166	    if (is_error()) {
167	      len = 0;
168	      return;
169	    }
170	    if ((b & 0x80) == 0) {
171	      len = b;
172	      if (len > MAX_CONVERT_LEN) {
173	        set_error();
174	        len = 0;
175	      }
176	      return;
177	    }
178	    if ((b & 0x40) == 0) {
179	      len = b & 0x3f;
180	      convert(b);
181	      len = (len << 8) | b;
182	      if (is_error())
183	        len = 0;
184	      else if (len > MAX_CONVERT_LEN) {
185	        set_error();
186	        len = 0;
187	      }
188	      return;
189	    }
190	    if ((b & 0x20) == 0) {
191	      len = b & 0x1f;
192	      convert(b);
193	      len = (len << 8) | b;
194	      convert(b);
195	      len = (len << 8) | b;
196	      if (is_error())
197	        len = 0;
198	      else if (len > MAX_CONVERT_LEN) {
199	        set_error();
200	        len = 0;
201	      }
202	      return;
203	    }
204	    len = b & 0x1f;
205	    convert(b);
206	    len = (len << 8) | b;
207	    convert(b);
208	    len = (len << 8) | b;
209	    convert(b);
210	    len = (len << 8) | b;
211	    if (is_error())
212	      len = 0;
213	    else if (len > MAX_CONVERT_LEN) {
214	      set_error();
215	      len = 0;
216	    }
217	  }
218	}
