7	error_t ec_pve_t::encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve,
8	                          const bn_t& _x) {
9	  error_t rv = UNINITIALIZED_ERROR;
10	  const auto& G = curve.generator();
11	  const mod_t& q = curve.order();
12	
13	  bn_t bn_x = _x % q;
14	  ecc_point_t Q_local = bn_x * G;
15	  buf128_t r0[kappa];
16	  buf128_t r1[kappa];
17	  buf_t c0[kappa];
18	  buf_t c1[kappa];
19	  ecc_point_t X0[kappa];
20	  ecc_point_t X1[kappa];
21	  buf_t L_local = buf_t(label);
22	  buf_t inner_label = genPVELabelWithPoint(label, Q_local);
23	  bn_t x_rows_local[kappa];
24	  buf128_t r_local[kappa];
25	  buf_t c_local[kappa];
26	
27	  for (int i = 0; i < kappa; i++) {
28	    bn_t x0, x1;
29	
30	    crypto::gen_random(r0[i]);
31	    crypto::gen_random(r1[i]);
32	    crypto::drbg_aes_ctr_t drbg0(r0[i]);
33	    crypto::drbg_aes_ctr_t drbg1(r1[i]);
34	
35	    x0 = drbg0.gen_bn(q);
36	    buf_t rho0 = drbg0.gen(rho_size);
37	
38	    MODULO(q) x1 = bn_x - x0;
39	    buf_t rho1 = drbg1.gen(rho_size);
40	
41	    if (rv = base_pke.encrypt(ek, inner_label, x0.to_bin(), rho0, c0[i])) return rv;
42	    X0[i] = x0 * G;
43	    if (rv = base_pke.encrypt(ek, inner_label, x1.to_bin(), rho1, c1[i])) return rv;
44	    X1[i] = Q_local - X0[i];
45	
46	    x_rows_local[i] = x1;  // output. will be cleared out if later bi == 0
47	  }
48	
49	  buf128_t b_local;
50	  b_local = crypto::ro::hash_string(Q_local, label, c0, c1, X0, X1).bitlen(kappa);
51	
52	  for (int i = 0; i < kappa; i++) {
53	    bool bi = b_local.get_bit(i);
54	    r_local[i] = bi ? r1[i] : r0[i];
55	    c_local[i] = bi ? c0[i] : c1[i];
56	    if (!bi) x_rows_local[i] = 0;  // clear the output
57	  }
58	
59	  Q = std::move(Q_local);
60	  L = std::move(L_local);
61	  b = b_local;
62	  for (int i = 0; i < kappa; i++) {
63	    x_rows[i] = std::move(x_rows_local[i]);
64	    r[i] = r_local[i];
65	    c[i] = std::move(c_local[i]);
66	  }
67	  return SUCCESS;
68	}
69	
70	error_t ec_pve_t::verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const ecc_point_t& Q, mem_t label) const {
71	  error_t rv = UNINITIALIZED_ERROR;
72	  ecurve_t curve = Q.get_curve();
73	  if (rv = curve.check(Q)) return coinbase::error(rv, "ec_pve_t::verify: check Q failed");
74	  if (Q != this->Q) return coinbase::error(E_CRYPTO, "public key (Q) mismatch");
75	  if (label != L) return coinbase::error(E_CRYPTO, "label mismatch");
76	  buf_t inner_label = genPVELabelWithPoint(label, Q);
77	
78	  const auto& G = curve.generator();
79	  const mod_t& q = curve.order();
80	  const int max_scalar_size = q.get_bin_size();
81	
82	  buf_t c0[kappa];
83	  buf_t c1[kappa];
84	  ecc_point_t X0[kappa];
85	  ecc_point_t X1[kappa];
86	
87	  for (int i = 0; i < kappa; i++) {
88	    if (x_rows[i].get_bin_size() > max_scalar_size) return coinbase::error(E_CRYPTO);
89	    if (!q.is_in_range(x_rows[i])) return coinbase::error(E_CRYPTO);
90	
91	    bool bi = b.get_bit(i);
92	
93	    crypto::drbg_aes_ctr_t drbg(r[i]);
94	
95	    bn_t xi;
96	    if (bi)
97	      xi = x_rows[i];
98	    else
99	      xi = drbg.gen_bn(q);
100	    buf_t rho = drbg.gen(rho_size);
101	
102	    X0[i] = xi * G;
103	    X1[i] = Q - X0[i];
104	    if (rv = base_pke.encrypt(ek, inner_label, xi.to_bin(), rho, c0[i])) return rv;
105	    c1[i] = c[i];
106	
107	    if (bi) {
108	      std::swap(X0[i], X1[i]);
109	      std::swap(c0[i], c1[i]);
110	    }
111	  }
112	
113	  buf_t b_tag = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(kappa);
114	  if (b_tag != b) return coinbase::error(E_CRYPTO, "b' != b");
115	  return SUCCESS;
116	}
117	
118	error_t ec_pve_t::restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve, bn_t& x_value) const {
119	  const mod_t& q = curve.order();
120	  const auto& G = curve.generator();
121	  const int max_scalar_size = q.get_bin_size();
122	
123	  bool bi = b.get_bit(row_index);
124	  if (decrypted_x_buf.size > max_scalar_size) return coinbase::error(E_CRYPTO);
125	  bn_t x_bi_bar = bn_t::from_bin(decrypted_x_buf);
126	  if (!q.is_in_range(x_bi_bar)) return coinbase::error(E_CRYPTO);
127	
128	  bn_t x_bi;
129	  if (bi) {
130	    if (x_rows[row_index].get_bin_size() > max_scalar_size) return coinbase::error(E_CRYPTO);
131	    if (!q.is_in_range(x_rows[row_index])) return coinbase::error(E_CRYPTO);
132	    x_bi = x_rows[row_index];
133	  } else {
134	    crypto::drbg_aes_ctr_t drbg0(r[row_index]);
135	    x_bi = drbg0.gen_bn(q);
136	  }
137	
138	  MODULO(q) x_value = x_bi_bar + x_bi;
