35	class unified_key_blob_base_pke_t final : public base_pke_i {
36	 public:
37	  error_t encrypt(mem_t ek, mem_t label, mem_t plain, mem_t rho, buf_t& out_ct) const override {
38	    base_pke_ek_blob_v1_t blob;
39	    error_t rv = parse_ek_blob(ek, blob);
40	    if (rv) return rv;
41	
42	    switch (static_cast<base_pke_key_type_v1>(blob.key_type)) {
43	      case base_pke_key_type_v1::rsa_oaep_2048:
44	        return coinbase::mpc::pve_base_pke_rsa().encrypt(coinbase::mpc::pve_keyref(blob.rsa_ek), label, plain, rho,
45	                                                         out_ct);
46	      case base_pke_key_type_v1::ecies_p256:
47	        if (blob.ecies_ek.get_curve() != coinbase::crypto::curve_p256)
48	          return coinbase::error(E_BADARG, "ECIES base PKE key must be on P-256");
49	        return coinbase::mpc::pve_base_pke_ecies().encrypt(coinbase::mpc::pve_keyref(blob.ecies_ek), label, plain, rho,
50	                                                           out_ct);
51	      default:
52	        return coinbase::error(E_FORMAT, "unsupported base PKE key type");
53	    }
54	  }
55	
56	  error_t decrypt(mem_t dk, mem_t label, mem_t ct, buf_t& out_plain) const override {
57	    base_pke_dk_blob_v1_t blob;
58	    error_t rv = parse_dk_blob(dk, blob);
59	    if (rv) return rv;
60	
61	    switch (static_cast<base_pke_key_type_v1>(blob.key_type)) {
62	      case base_pke_key_type_v1::rsa_oaep_2048:
63	        return coinbase::mpc::pve_base_pke_rsa().decrypt(coinbase::mpc::pve_keyref(blob.rsa_dk), label, ct, out_plain);
64	      case base_pke_key_type_v1::ecies_p256:
65	        if (blob.ecies_dk.get_curve() != coinbase::crypto::curve_p256)
66	          return coinbase::error(E_BADARG, "ECIES base PKE key must be on P-256");
67	        return coinbase::mpc::pve_base_pke_ecies().decrypt(coinbase::mpc::pve_keyref(blob.ecies_dk), label, ct,
68	                                                           out_plain);
69	      default:
70	        return coinbase::error(E_FORMAT, "unsupported base PKE key type");
71	    }
72	  }
73	};
