118	error_t base_pke_ecies_p256_ek_from_oct(mem_t pub_key_oct, buf_t& out_ek) {
119	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(pub_key_oct, "pub_key_oct",
120	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
121	    return rv;
122	  error_t rv = UNINITIALIZED_ERROR;
123	
124	  coinbase::crypto::ecc_pub_key_t pk;
125	  if (rv = pk.from_oct(coinbase::crypto::curve_p256, pub_key_oct)) return rv;
126	  if (rv = coinbase::crypto::curve_p256.check(pk)) return rv;
127	
128	  base_pke_ek_blob_v1_t ek_blob;
129	  ek_blob.key_type = static_cast<uint32_t>(base_pke_key_type_v1::ecies_p256);
130	  ek_blob.ecies_ek = std::move(pk);
131	
132	  out_ek = coinbase::convert(ek_blob);
133	  return SUCCESS;
134	}
