175	error_t encrypt(const base_pke_i& base_pke, curve_id curve, mem_t ek, mem_t label, mem_t x, buf_t& out_ciphertext) {
176	  if (const error_t rv =
177	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
178	    return rv;
179	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
180	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(x, "x")) return rv;
181	  error_t rv = UNINITIALIZED_ERROR;
182	
183	  const auto icurve = to_internal_curve(curve);
184	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
185	
186	  // Defensive check: avoid large attacker-controlled allocations when converting `x` into a bignum.
187	  const int max_x_size = icurve.order().get_bin_size();
188	  if (x.size > max_x_size) return coinbase::error(E_RANGE, "x too large", /*to_print_stack_trace=*/false);
189	
190	  base_pke_bridge_t bridge(base_pke);
191	  coinbase::mpc::ec_pve_t pve_ct;
192	
193	  const coinbase::mem_t ek_mem(ek.data, ek.size);
194	  const coinbase::crypto::bn_t x_bn = coinbase::crypto::bn_t::from_bin(x);
195	
196	  out_ciphertext.free();
197	  rv = pve_ct.encrypt(bridge, coinbase::mpc::pve_keyref(ek_mem), label, icurve, x_bn);
198	  if (rv) return rv;
199	
200	  pve_ciphertext_blob_v1_t blob;
201	  blob.ct = coinbase::convert(pve_ct);
202	  out_ciphertext = coinbase::convert(blob);
203	  return SUCCESS;
204	}
