210	error_t verify(const base_pke_i& base_pke, curve_id curve, mem_t ek, mem_t ciphertext, mem_t Q_compressed,
211	               mem_t label) {
212	  if (const error_t rv =
213	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
214	    return rv;
215	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
216	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
217	    return rv;
218	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(Q_compressed, "Q_compressed")) return rv;
219	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
220	  error_t rv = UNINITIALIZED_ERROR;
221	
222	  const auto icurve = to_internal_curve(curve);
223	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
224	
225	  pve_ciphertext_blob_v1_t blob;
226	  if (rv = coinbase::convert(blob, ciphertext)) return rv;
227	  if (blob.version != pve_ciphertext_version_v1) return coinbase::error(E_FORMAT, "unsupported ciphertext version");
228	
229	  base_pke_bridge_t bridge(base_pke);
230	  coinbase::mpc::ec_pve_t pve_ct;
231	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
232	
233	  if (pve_ct.get_Q().get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
234	
235	  coinbase::crypto::ecc_point_t Q_expected;
236	  if (rv = Q_expected.from_bin(icurve, Q_compressed)) return coinbase::error(rv, "invalid Q");
237	  if (rv = icurve.check(Q_expected)) return coinbase::error(rv, "invalid Q");
238	
239	  const coinbase::mem_t ek_mem(ek.data, ek.size);
240	  return pve_ct.verify(bridge, coinbase::mpc::pve_keyref(ek_mem), Q_expected, label);
241	}
