251	    return rv;
252	  if (const error_t rv =
253	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
254	    return rv;
255	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
256	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
257	    return rv;
258	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(label, "label")) return rv;
259	  error_t rv = UNINITIALIZED_ERROR;
260	
261	  const auto icurve = to_internal_curve(curve);
262	  if (!icurve.valid()) return coinbase::error(E_BADARG, "unsupported curve");
263	
264	  pve_ciphertext_blob_v1_t blob;
265	  if (rv = coinbase::convert(blob, ciphertext)) return rv;
266	  if (blob.version != pve_ciphertext_version_v1) return coinbase::error(E_FORMAT, "unsupported ciphertext version");
267	
268	  base_pke_bridge_t bridge(base_pke);
269	  coinbase::mpc::ec_pve_t pve_ct;
270	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
271	
272	  if (pve_ct.get_Q().get_curve() != icurve) return coinbase::error(E_BADARG, "ciphertext curve mismatch");
273	
274	  const coinbase::mem_t dk_mem(dk.data, dk.size);
275	  const coinbase::mem_t ek_mem(ek.data, ek.size);
276	
277	  coinbase::crypto::bn_t x_bn;
278	  rv = pve_ct.decrypt(bridge, coinbase::mpc::pve_keyref(dk_mem), coinbase::mpc::pve_keyref(ek_mem), label, icurve, x_bn,
279	                      /*skip_verify=*/true);
280	  if (rv) {
281	    out_x.free();
282	    return rv;
283	  }
284	
285	  out_x = x_bn.to_bin(icurve.order().get_bin_size());
286	  return SUCCESS;
287	}
