5	error_t ec_pve_batch_t::encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve,
6	                                const std::vector<bn_t>& _x) {
7	  error_t rv = UNINITIALIZED_ERROR;
8	  cb_assert(n > 0 && n <= MAX_BATCH_COUNT);
9	  cb_assert(int(_x.size()) == n);
10	
11	  const mod_t& q = curve.order();
12	  const auto& G = curve.generator();
13	  int curve_size = curve.size();
14	  std::vector<bn_t> x(n);
15	
16	  for (int j = 0; j < n; j++) {
17	    x[j] = _x[j] % q;
18	    Q[j] = x[j] * G;
19	  }
20	
21	  buf128_t r01[kappa], r02[kappa];
22	  buf128_t r1[kappa];
23	  buf_t c0[kappa];
24	  buf_t c1[kappa];
25	  std::vector<ecc_point_t> X0[kappa];
26	  std::vector<ecc_point_t> X1[kappa];
27	  L = buf_t(label);
28	  buf_t inner_label = genPVELabelWithPoint(label, Q);
29	
30	  for (int i = 0; i < kappa; i++) {
31	    X0[i].resize(n);
32	    X1[i].resize(n);
33	
34	    crypto::gen_random(r01[i]);
35	    crypto::gen_random(r02[i]);
36	    crypto::gen_random(r1[i]);
37	    crypto::drbg_aes_ctr_t drbg01(r01[i]);
38	    crypto::drbg_aes_ctr_t drbg02(r02[i]);
39	    crypto::drbg_aes_ctr_t drbg1(r1[i]);
40	
41	    buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
42	    buf_t rho0 = drbg02.gen(rho_size);
43	    buf_t rho1 = drbg1.gen(rho_size);
44	
45	    std::vector<bn_t> x0;
46	    if (rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, x0))
47	      return rv;
48	    std::vector<bn_t> x1(n);
49	    for (int j = 0; j < n; j++) {
50	      MODULO(q) x1[j] = x[j] - x0[j];
51	
52	      X0[i][j] = x0[j] * G;
53	      X1[i][j] = Q[j] - X0[i][j];
54	    }
55	
56	    buf_t x1_bin = bn_t::vector_to_bin(x1, curve_size);
57	
58	    if (rv = base_pke.encrypt(ek, inner_label, r01[i], rho0, c0[i])) return rv;
59	    if (rv = base_pke.encrypt(ek, inner_label, x1_bin, rho1, c1[i])) return rv;
60	    rows[i].x_bin = x1_bin;  // some of these will be reset to zero later based on `bi`
61	  }
62	
63	  b = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(kappa);
64	
65	  for (int i = 0; i < kappa; i++) {
66	    bool bi = b.get_bit(i);
67	    rows[i].r = bi ? r1[i] : (r01[i] + r02[i]);
68	    rows[i].c = bi ? c0[i] : c1[i];
69	    if (!bi) rows[i].x_bin.free();
70	  }
71	  return SUCCESS;
72	}
73	
74	error_t ec_pve_batch_t::verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const std::vector<ecc_point_t>& Q,
75	                               mem_t label) const {
76	  error_t rv = UNINITIALIZED_ERROR;
77	  if (n <= 0 || n > MAX_BATCH_COUNT) return coinbase::error(E_BADARG);
78	  if (int(Q.size()) != n) return coinbase::error(E_BADARG);
79	
80	  // This verifies that the input Q values are the same as backed up Q values (step 2 of spec)
81	  // and that the input Q values are on curve (step 1 of spec) assuming backed up one is on curve
82	  ecurve_t curve = Q[0].get_curve();
83	  for (int i = 0; i < n; i++) {
84	    if (rv = curve.check(Q[i])) return coinbase::error(rv, "ec_pve_batch_t::verify: check Q[i] failed");
85	  }
86	  if (Q != this->Q) return coinbase::error(E_CRYPTO, "public keys (Qs) mismatch");
87	  if (label != this->L) return coinbase::error(E_CRYPTO);
88	  buf_t inner_label = genPVELabelWithPoint(label, Q);
89	
90	  const auto& G = curve.generator();
91	  const mod_t& q = curve.order();
92	  int curve_size = curve.size();
93	
94	  buf_t c0[kappa];
95	  buf_t c1[kappa];
96	  std::vector<ecc_point_t> X0[kappa];
97	  std::vector<ecc_point_t> X1[kappa];
98	
99	  for (int i = 0; i < kappa; i++) {
100	    bool bi = b.get_bit(i);
101	    // xi is x^0_i or x^1_i depends on bi == 1 or 0.
102	    // Note that we always have X[0][i] = xi * G, then X[0] and X[1] if xi is x^1_i.
103	    std::vector<bn_t> xi;
104	    if (bi) {
105	      c0[i] = rows[i].c;
106	
107	      if (rows[i].r.size() != 16) return coinbase::error(E_CRYPTO);
108	      if (rows[i].x_bin.size() != n * curve_size) return coinbase::error(E_CRYPTO);
109	      if (rv = bn_t::vector_from_bin(rows[i].x_bin, n, curve_size, q, xi)) return rv;
110	      crypto::drbg_aes_ctr_t drbg1(rows[i].r);
111	      buf_t rho1 = drbg1.gen(rho_size);
112	
113	      if (rv = base_pke.encrypt(ek, inner_label, bn_t::vector_to_bin(xi, curve_size), rho1, c1[i])) return rv;
114	    } else {
115	      c1[i] = rows[i].c;
116	
117	      if (rows[i].r.size() != 32) return coinbase::error(E_CRYPTO);
118	      crypto::drbg_aes_ctr_t drbg01(rows[i].r.take(16));
119	      buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
120	      if (rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, xi))
121	        return rv;
122	
123	      crypto::drbg_aes_ctr_t drbg02(rows[i].r.skip(16));
124	      buf_t rho0 = drbg02.gen(rho_size);
125	
126	      if (rv = base_pke.encrypt(ek, inner_label, rows[i].r.take(16), rho0, c0[i])) return rv;
127	    }
128	
129	    X0[i].resize(n);
130	    X1[i].resize(n);
131	    for (int j = 0; j < n; j++) {
132	      X0[i][j] = xi[j] * G;
133	      X1[i][j] = Q[j] - X0[i][j];
134	    }
135	
136	    if (bi) std::swap(X0[i], X1[i]);
137	  }
138	
139	  buf_t b_tag = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(SEC_P_COM);
140	  if (b_tag != b) return coinbase::error(E_CRYPTO);
141	  return SUCCESS;
142	}
143	
144	error_t ec_pve_batch_t::restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve,
145	                                               std::vector<bn_t>& x) const {
146	  if (row_index < 0 || row_index >= kappa) return coinbase::error(E_BADARG);
147	
148	  const mod_t& q = curve.order();
149	  const auto& G = curve.generator();
150	  int curve_size = curve.size();
151	
152	  const row_t& row = rows[row_index];
153	  const bool bi = b.get_bit(row_index);
154	
155	  mem_t r01;
156	  mem_t x1_bin;
157	  if (bi) {
158	    // When bi=1, the opened value is x1_bin (stored), and the unopened value is r01 (decrypted).
159	    if (row.x_bin.size() != n * curve_size) return coinbase::error(E_CRYPTO);
160	    x1_bin = row.x_bin;
161	    r01 = decrypted_x_buf;
162	    if (r01.size != 16) return coinbase::error(E_CRYPTO);
163	  } else {
164	    // When bi=0, the opened value is r01||r02 (stored in row.r), and the unopened value is x1_bin (decrypted).
165	    if (row.r.size() != 32) return coinbase::error(E_CRYPTO);
166	    r01 = row.r.take(16);
167	    x1_bin = decrypted_x_buf;
168	    if (x1_bin.size != n * curve_size) return coinbase::error(E_CRYPTO);
169	  }
170	
171	  crypto::drbg_aes_ctr_t drbg01(r01);
172	  buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
173	  std::vector<bn_t> x0;
174	  error_t rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, x0);
175	  if (rv) return rv;
176	
177	  std::vector<bn_t> x1;
178	  rv = bn_t::vector_from_bin(x1_bin, n, curve_size, q, x1);
179	  if (rv) return rv;
180	
181	  for (int i = 0; i < n; i++) {
182	    MODULO(q) x[i] = x0[i] + x1[i];
183	    if (Q[i] != x[i] * G) return coinbase::error(E_CRYPTO);
184	  }
185	
186	  return SUCCESS;
187	}
188	
189	error_t ec_pve_batch_t::decrypt(const pve_base_pke_i& base_pke, pve_keyref_t dk, pve_keyref_t ek, mem_t label,
190	                                ecurve_t curve, std::vector<bn_t>& xs, bool skip_verify) const {
191	  error_t rv = UNINITIALIZED_ERROR;
192	  xs.resize(n);
193	  if (!skip_verify && (rv = verify(base_pke, ek, Q, label))) return rv;
194	
195	  if (label != this->L) return coinbase::error(E_CRYPTO);
196	  buf_t inner_label = genPVELabelWithPoint(label, Q);
197	
198	  for (int i = 0; i < kappa; i++) {
199	    buf_t x_buf;
200	    if (rv = base_pke.decrypt(dk, inner_label, rows[i].c, x_buf)) continue;
201	    if (restore_from_decrypted(i, x_buf, curve, xs) == SUCCESS) return SUCCESS;
202	  }
203	
204	  xs.clear();
205	  return coinbase::error(E_CRYPTO);
206	}
