193	error_t decrypt_batch_rsa_oaep_hsm(curve_id curve, mem_t dk_handle, mem_t ek, mem_t ciphertext, mem_t label,
194	                                   const rsa_oaep_hsm_decap_cb_t& cb, std::vector<buf_t>& out_xs) {
195	  if (const error_t rv = coinbase::api::detail::validate_mem_arg(dk_handle, "dk_handle")) return rv;
196	  if (const error_t rv =
197	          coinbase::api::detail::validate_mem_arg_max_size(ek, "ek", coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
198	    return rv;
199	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
