250	error_t get_public_keys_compressed_batch(mem_t ciphertext, std::vector<buf_t>& out_Qs_compressed) {
251	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(
252	          ciphertext, "ciphertext", coinbase::api::detail::MAX_CIPHERTEXT_BLOB_SIZE))
253	    return rv;
254	  error_t rv = UNINITIALIZED_ERROR;
255	
256	  pve_batch_ciphertext_blob_v1_t blob;
257	  if (rv = parse_batch_ciphertext(ciphertext, blob)) return rv;
258	
259	  const int n = static_cast<int>(blob.batch_count);
260	  coinbase::mpc::ec_pve_batch_t pve_ct(n);  // base PKE not used for extraction
261	  if (rv = coinbase::convert(pve_ct, blob.ct)) return rv;
262	
263	  std::vector<buf_t> out_local;
264	  out_local.reserve(static_cast<size_t>(n));
265	  for (const auto& q : pve_ct.get_Qs()) out_local.push_back(q.to_compressed_bin());
266	
267	  out_Qs_compressed = std::move(out_local);
268	  return SUCCESS;
269	}
